// Reset error state
  context.component.variables['error'] = '';

  // Validate file
  if (!context.parameters['file']) {
    context.component.variables['error'] = 'No file provided';
    return;
  }

  // Validate file type
  if (!context.parameters['file'].name.toLowerCase().endsWith('.csv')) {
    context.component.variables['error'] = 'Invalid file type. Please upload a CSV file';
    return;
  }

  // Set loading state
  context.component.variables['isLoading'] = true;

  // Use FileReader to read the file
  const reader = new FileReader();

  reader.onload = (event) => {
    try {
      const csvContent = event.target.result;

      // Basic CSV parsing (could be enhanced with a library in a real app)
      const lines = csvContent.split('\n');

      // Handle empty file
      if (lines.length === 0) {
        context.component.variables['error'] = 'The CSV file is empty';
        context.component.variables['isLoading'] = false;
        return;
      }

      // Parse headers (first line)
      const headers = lines[0].split(',').map(header => header.trim().replace(/^"(.*)"$/, '$1'));

      // Parse data rows
      const data = [];
      for (let i = 1; i < lines.length; i++) {
        if (lines[i].trim() === '') continue; // Skip empty lines

        // Handle quoted values with commas inside
        const row = {};
        let currentLine = lines[i];
        let values = [];

        // Simple CSV parsing (handles basic quoted values)
        let inQuotes = false;
        let currentValue = '';

        for (let j = 0; j < currentLine.length; j++) {
          const char = currentLine[j];

          if (char === '"' && (j === 0 || currentLine[j-1] !== '\\')) {
            inQuotes = !inQuotes;
          } else if (char === ',' && !inQuotes) {
            values.push(currentValue.trim().replace(/^"(.*)"$/, '$1'));
            currentValue = '';
          } else {
            currentValue += char;
          }
        }

        // Add the last value
        values.push(currentValue.trim().replace(/^"(.*)"$/, '$1'));

        // Create row object with headers as keys
        for (let j = 0; j < headers.length; j++) {
          row[headers[j]] = values[j] || '';
        }

        // Add row ID for the grid
        row.id = i;

        data.push(row);
      }

      // Update component variables
      context.component.variables['headers'] = headers;
      context.component.variables['parsedData'] = data;
      context.component.variables['isLoading'] = false;

    } catch (error) {
      console.error('Error parsing CSV:', error);
      context.component.variables['error'] = 'Error parsing CSV file: ' + error.message;
      context.component.variables['isLoading'] = false;
    }
  };

